// Define the inboxes to scan
// daniel@ is excluded — that is Dan's personal inbox, no automation
const inboxes = [
  { address: 'support@syntharra.com',    label: 'Support',    priority: 'high',   icon: '🎧' },
  { address: 'sales@syntharra.com',       label: 'Sales',      priority: 'high',   icon: '💼' },
  { address: 'info@syntharra.com',        label: 'Info',       priority: 'medium', icon: 'ℹ️' },
  { address: 'solutions@syntharra.com',   label: 'Solutions',  priority: 'high',   icon: '🔧' },
  { address: 'alerts@syntharra.com',      label: 'Alerts',     priority: 'high',   icon: '🔔' },
  { address: 'admin@syntharra.com',       label: 'Admin',      priority: 'medium', icon: '⚙️' },
  { address: 'careers@syntharra.com',     label: 'Careers',    priority: 'medium', icon: '💼' }
];

return inboxes.map(inbox => ({ json: inbox }));

// Extract and clean email data
const items = $input.all();
const results = [];

for (const item of items) {
  const msg = item.json;
  if (!msg || !msg.id || msg.error) continue;

  // Extract headers
  const headers = msg.payload?.headers || [];
  const getHeader = (name) => headers.find(h => h.name?.toLowerCase() === name.toLowerCase())?.value || '';

  const subject  = getHeader('Subject')   || '(no subject)';
  const from     = getHeader('From')       || 'Unknown';
  const to       = getHeader('To')         || '';
  const date     = getHeader('Date')       || '';
  const replyTo  = getHeader('Reply-To')   || from;

  // Get body snippet
  const snippet = msg.snippet || '';

  // Determine which inbox this came from (look at 'To' field)
  const toAddr = to.toLowerCase();
  let inboxLabel = 'Unknown';
  let inboxAddress = toAddr;
  const inboxMap = {
    'support': 'Support',
    'sales': 'Sales',
    'info': 'Info',
    'solutions': 'Solutions',
    'alerts': 'Alerts',
    'admin': 'Admin',
    'careers': 'Careers'
  };
  for (const [key, val] of Object.entries(inboxMap)) {
    if (toAddr.includes(key + '@syntharra')) { inboxLabel = val; inboxAddress = key + '@syntharra.com'; break; }
  }

  // Get the parent inbox info from earlier in the chain
  const parentAddress = $('Define Inboxes').item?.json?.address || '';
  if (inboxAddress === 'unknown' && parentAddress) {
    inboxAddress = parentAddress;
    for (const [key, val] of Object.entries(inboxMap)) {
      if (parentAddress.includes(key)) { inboxLabel = val; break; }
    }
  }

  results.push({
    email_id: msg.id,
    thread_id: msg.threadId,
    inbox_address: inboxAddress || parentAddress,
    inbox_label: inboxLabel,
    subject: subject.substring(0, 300),
    from_address: from.substring(0, 200),
    snippet: snippet.substring(0, 500),
    received_at: msg.internalDate ? new Date(parseInt(msg.internalDate)).toISOString() : new Date().toISOString(),
    label_ids: (msg.labelIds || []).join(','),
    is_unread: (msg.labelIds || []).includes('UNREAD')
  });
}

return results.map(r => ({ json: r }));

// Check if there are any emails to process
const items = $input.all();
const emails = items.filter(i => i.json && i.json.email_id);

if (emails.length === 0) {
  // No emails — still write a digest record showing all-clear
  return [{ json: { skip: true, count: 0 } }];
}

// Group by inbox
const grouped = {};
for (const item of emails) {
  const addr = item.json.inbox_address || 'unknown';
  if (!grouped[addr]) grouped[addr] = [];
  grouped[addr].push(item.json);
}

// Pass each inbox group forward for AI classification
const output = [];
for (const [addr, msgs] of Object.entries(grouped)) {
  output.push({ json: { inbox_address: addr, emails: msgs, count: msgs.length } });
}

return output;

// Build AI prompt for email importance classification
const inbox = $json.inbox_address || 'unknown';
const emails = $json.emails || [];
const count = emails.length;

if ($json.skip) {
  return [{ json: { skip: true } }];
}

// Format emails for AI
const emailList = emails.map((e, i) => {
  return `Email ${i+1}:
  From: ${e.from_address}
  Subject: ${e.subject}
  Preview: ${e.snippet}`;
}).join('\n\n');

const prompt = `You are reviewing emails received at ${inbox} for an AI Solutions company called Syntharra.
Syntharra sells AI Phone Receptionists to trade businesses (HVAC, plumbing, electrical, etc.) in the USA.

Review these ${count} unread emails and classify each one. 

For each email, output ONLY a JSON array (no other text) with this structure:
[
  {
    "index": 1,
    "importance": "high" | "medium" | "low" | "ignore",
    "category": "client_enquiry" | "sales_lead" | "job_application" | "support_request" | "partnership" | "complaint" | "invoice" | "automated" | "spam" | "other",
    "action_required": true | false,
    "summary": "One sentence summary of what this email is about and what action if any is needed",
    "flag": null | "urgent" | "opportunity" | "hire"
  }
]

IMPORTANCE RULES (be generous — when in doubt, mark higher importance):
- "high": Real person emailing about business — enquiries, sales, support issues, complaints, partnerships, job applications from candidates who look qualified
- "medium": Could be relevant — newsletters from key vendors, invoices, automated alerts that may need attention
- "low": Automated reports, notifications, system emails that are informational only
- "ignore": Clear promotional spam, marketing blasts, mass newsletters, automated receipts with no action needed

NEVER mark as "ignore" anything that looks like a real human emailing us directly.

Emails to classify:
${emailList}`;

return [{ json: { inbox_address: inbox, prompt, email_data: emails, count } }];

// Parse AI classification and merge with email data
const items = $input.all();
const results = [];

for (const item of items) {
  const { inbox_address, email_data, count } = item.json;
  if (item.json.skip) continue;

  // Parse Groq response
  let classifications = [];
  try {
    const content = item.json.choices?.[0]?.message?.content || '[]';
    // Strip any markdown code fences
    const clean = content.replace(/```json|```/g, '').trim();
    classifications = JSON.parse(clean);
  } catch (e) {
    // If parsing fails, mark everything as medium/other
    classifications = (email_data || []).map((_, i) => ({
      index: i + 1,
      importance: 'medium',
      category: 'other',
      action_required: true,
      summary: 'Could not classify — manual review needed',
      flag: null
    }));
  }

  // Merge classifications with email data
  for (const cls of classifications) {
    const emailIdx = cls.index - 1;
    const emailData = (email_data || [])[emailIdx] || {};

    // Skip emails marked as ignore
    if (cls.importance === 'ignore') continue;

    results.push({
      inbox_address: inbox_address,
      inbox_label: emailData.inbox_label || inbox_address.split('@')[0],
      email_id: emailData.email_id || null,
      thread_id: emailData.thread_id || null,
      from_address: emailData.from_address || '',
      subject: emailData.subject || '(no subject)',
      snippet: emailData.snippet || '',
      received_at: emailData.received_at || new Date().toISOString(),
      importance: cls.importance || 'medium',
      category: cls.category || 'other',
      action_required: cls.action_required === true,
      ai_summary: cls.summary || '',
      flag: cls.flag || null,
      digest_date: new Date().toISOString().split('T')[0],
      created_at: new Date().toISOString()
    });
  }
}

// If no important emails, return a no-op
if (results.length === 0) {
  return [{ json: { no_important_emails: true } }];
}

return results.map(r => ({ json: r }));

// First, clear today's digest records (so re-runs are idempotent)
// Then insert fresh records
const items = $input.all();
const validItems = items.filter(i => i.json && !i.json.no_important_emails && i.json.inbox_address);

if (validItems.length === 0) {
  return [{ json: { inserted: 0, message: 'No important emails to save' } }];
}

const today = new Date().toISOString().split('T')[0];
const SUPABASE_URL = 'https://hgheyqwnrcvwtgngqdnq.supabase.co';
const SERVICE_ROLE_KEY = process.env.SUPABASE_SERVICE_ROLE_KEY;

if (!SERVICE_ROLE_KEY) {
  throw new Error('SUPABASE_SERVICE_ROLE_KEY not set in environment variables');
}

// Clear today's records first
await fetch(`${SUPABASE_URL}/rest/v1/email_digest?digest_date=eq.${today}`, {
  method: 'DELETE',
  headers: {
    'apikey': SERVICE_ROLE_KEY,
    'Authorization': `Bearer ${SERVICE_ROLE_KEY}`,
    'Content-Type': 'application/json'
  }
});

// Insert new records
const records = validItems.map(i => i.json);
const response = await fetch(`${SUPABASE_URL}/rest/v1/email_digest`, {
  method: 'POST',
  headers: {
    'apikey': SERVICE_ROLE_KEY,
    'Authorization': `Bearer ${SERVICE_ROLE_KEY}`,
    'Content-Type': 'application/json',
    'Prefer': 'return=minimal'
  },
  body: JSON.stringify(records)
});

if (!response.ok) {
  const err = await response.text();
  throw new Error(`Supabase insert failed: ${err}`);
}

return [{ json: { inserted: records.length, digest_date: today, message: `Saved ${records.length} important emails to digest` } }];
